<script setup lang="ts">
	// types
	type Props = {
		logoHeight?: string
		logoBgColor?: 'default' | 'inverse' | 'transparent'
		logoTextColor?: 'primary' | 'inverse'
	}

	// props
	const {
		logoHeight = '40px',
		logoBgColor = 'transparent',
		logoTextColor = 'primary',
	} = defineProps<Props>()

	const bgFill = (keyword: Props['logoBgColor']): string => {
		switch (keyword) {
			case 'default':
				return '#ffffff'
			case 'inverse':
				return '#1d6283'
			case 'transparent':
				return 'transparent'
			default:
				return 'transparent'
		}
	}

	const textFill = (keyword: Props['logoTextColor']): string => {
		switch (keyword) {
			case 'primary':
				return '#1d6283'
			case 'inverse':
				return '#ffffff'
			default:
				return 'transparent'
		}
	}
</script>
